const now=new Date().toISOString();
return [
 {json:{setting_key:'global',value:JSON.stringify({lot_size:20,interval_value:15,interval_unit:'minutes',anti_duplicate:true,attachment_retention_days:90}),updated_at:now}},
 {json:{setting_key:'smtp_policy',value:JSON.stringify({provider:'SkyMail',host:'smtp.example.com',port:465,ssl:true,retry_minutes:[15,60],max_attempts:3}),updated_at:now}}
];

const rows = (name) => {
  try { return $(name).all().map(i => i.json || {}).filter(x => Object.keys(x).length); }
  catch { return []; }
};
const parseSetting = (rows, key, fallback) => {
  const r = rows.find(x => x.setting_key === key);
  if (!r) return fallback;
  try { return JSON.parse(r.value); } catch { return r.value ?? fallback; }
};
const contacts = rows('DT Contatos');
const groups = rows('DT Grupos');
const memberships = rows('DT Membros');
const fs = require('fs');
function hydrateInline(html) {
  return String(html || '').replace(/\[\[INLINE\|([^|]+)\|([^|]+)\|([^\]]+)\]\]/g, (m,p,mime,name) => {
    try {
      const path=decodeURIComponent(p), mt=decodeURIComponent(mime), nm=decodeURIComponent(name);
      if(!fs.existsSync(path)) return '<p>[Imagem não encontrada: '+nm+']</p>';
      const b64=fs.readFileSync(path).toString('base64');
      return '<img src="data:'+mt+';base64,'+b64+'" alt="'+nm.replaceAll('"','&quot;')+'" style="max-width:100%;height:auto;border-radius:8px">';
    } catch { return m; }
  });
}
const campaigns = rows('DT Campanhas').map(c => ({...c,message_html:hydrateInline(c.message_html)}));
const recipients = rows('DT Destinatários');
const settings = rows('DT Configurações');
const suppressions = rows('DT Nunca Enviar');
const errors = rows('DT Erros');
const globalSetting = parseSetting(settings, 'global', {lot_size:20,interval_value:15,interval_unit:'minutes',anti_duplicate:true});

let signatureHtml = '';
try {
  signatureHtml = fs.readFileSync('/files/assinatura_vesper.html', 'utf8')
    .replace(/^﻿/, '')
    .replace(/<meta[^>]*>/gi, '')
    .replace(/<link[^>]*>/gi, '')
    .replace(/href=["']www\.vesper\.ind\.br["']/gi, 'href="http://www.example.com"');
} catch {
  signatureHtml = '<p>Atenciosamente,</p><strong style="color:#dc2626">Empresa Exemplo EX LTDA</strong><br><a href="mailto:remetente@example.com">remetente@example.com</a>';
}

