<script>
(function(){
'use strict';
var DATA=window.__MDV_DATA__;
var API=DATA.actionUrl;
var EXPORT_URL=DATA.exportUrl;
var state={page:'home',step:0,attachments:[],inlineImages:[],selected:new Set(),activeGroup:null};

function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]})}
function id(prefix){return prefix+'_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,8)}
function toast(title,text,error){var t=document.getElementById('toast');document.getElementById('toastTitle').textContent=title;document.getElementById('toastText').textContent=text;t.className='toast show'+(error?' error':'');setTimeout(function(){t.className='toast'},5000)}
function openModal(idv){document.getElementById(idv).classList.add('open')}
